/**
 * @generated by @flusk/cli
 * Template for TUI Ink screen components
 */

import { toPascalCase } from '../../generators/utils.js';

export function generateTuiScreenTemplate(name: string): string {
  const pascal = toPascalCase(name);
  return `/**
 * @generated by @flusk/cli — customize after generation
 * TUI Screen: ${pascal}
 */

import React from 'react';
import { Box, Text } from 'ink';
import { useApi } from '../hooks/use-api.js';

export interface ${pascal}ScreenProps {
  endpoint: string;
  apiKey: string;
}

export function ${pascal}Screen({ endpoint, apiKey }: ${pascal}ScreenProps) {
  const { data, loading, error } = useApi(
    endpoint, '/api/v1/${name}s', apiKey,
  );

  if (loading) return <Text>Loading ${name}...</Text>;
  if (error) return <Text color="red">Error: {error}</Text>;

  return (
    <Box flexDirection="column">
      <Text bold>${pascal}</Text>
      <Text>{JSON.stringify(data, null, 2)}</Text>
    </Box>
  );
}
`;
}
